    /* ── Suggested Reconstruction (Front) ── */
    (function initReconstruction() {
      const rawEl = document.getElementById('rawReconstruction');
      const rawText = rawEl ? rawEl.textContent.trim() : '';
      const reconstructBtn = document.getElementById('reconstructBtn');
      const hasReconstruction = rawText && rawText.length > 0 && !rawText.toLowerCase().includes('no reconstruction needed');
      if (hasReconstruction && reconstructBtn) {
        reconstructBtn.style.display = 'inline-flex';
      }
      /* Strip the correct‑answer line for front‑side display */
      function stripAnswerLine(text) {
        return text.replace(/^(?:Correct\\s*Answer|الإجابة\\s*الصحيحة|Answer)\\s*[:：]?\\s*.+/img, '').trim();
      }
      window.toggleReconstruction = function (e) {
        if (e) e.stopPropagation();
        const box = document.getElementById('reconstructionBox');
        const btn = document.getElementById('reconstructBtn');
        if (!box) return;
        if (box.style.display === 'none') {
          box.style.display = 'block';
          box.classList.remove('slide-down');
          void box.offsetWidth;
          box.classList.add('slide-down');
          /* Populate with filtered text (question + options only) */
          const contentEl = document.getElementById('reconstructionContent');
          if (contentEl) {
            contentEl.textContent = stripAnswerLine(rawText);
          }
          if (btn) {
            btn.classList.add('is-open');
            btn.textContent = '🔧 Hide Reconstruction';
          }
        } else {
          box.style.display = 'none';
          if (btn) {
            btn.classList.remove('is-open');
            btn.textContent = '🔧 Reconstruction';
          }
        }
      };
    })();
