        /* ── Conflict Popup (Back) ── */
        (function initConflict() {
            const rawConflict = document.getElementById('rawConflict');
            const conflictField = rawConflict ? rawConflict.textContent.trim() : '';
            const explanationEl = document.querySelector('.explanation');
            const explanationTxt = explanationEl ? explanationEl.textContent : '';
            /* ─ Keywords that suggest a conflicting or controversial answer ─ */
            const CONFLICT_KEYWORDS = [
                'controversial', 'debated', 'disputed', 'conflicting', 'some sources',
                'some books', 'traditionally', 'alternatively', 'varies', 'minority view',
                'not all sources', 'different sources', 'some guidelines',
                'مختلف', 'خلاف', 'جدلي', 'بعض المصادر', 'اختلف', 'تباين', 'يختلف', 'خلافي',
                'بعض الكتب', 'بعض المراجع', 'تقليدياً'
            ];
            const detectedKw = CONFLICT_KEYWORDS.find(kw =>
                explanationTxt.toLowerCase().includes(kw.toLowerCase())
            );
            const hasFieldConflict = conflictField.length > 0;
            const hasKeywordConflict = !!detectedKw;
            const shouldShow = hasFieldConflict || hasKeywordConflict;
            const conflictBtn = document.getElementById('conflictBtn');
            if (conflictBtn && shouldShow) {
                conflictBtn.style.display = 'inline-flex';
                if (hasKeywordConflict && !hasFieldConflict)
                    conflictBtn.classList.add('conflict-auto-detected');
            }
            window.openConflictPopup = function () {
                const pop = document.getElementById('conflictPopup');
                if (!pop) return;
                /* Auto-detection banner */
                const autoBanner = document.getElementById('conflictAutoBanner');
                const kwSpan = document.getElementById('conflictKeywordSpan');
                if (autoBanner && kwSpan) {
                    if (hasKeywordConflict) {
                        kwSpan.textContent = '“' + detectedKw + '”';
                        autoBanner.style.display = 'flex';
                    } else {
                        autoBanner.style.display = 'none';
                    }
                }
                /* Field content */
                const fieldBox = document.getElementById('conflictFieldBox');
                const fieldText = document.getElementById('conflictFieldText');
                if (hasFieldConflict && fieldBox && fieldText) {
                    fieldText.textContent = conflictField;
                    fieldBox.style.display = 'block';
                }
                pop.style.display = 'flex';
            };
            window.closeConflictPopup = function () {
                const pop = document.getElementById('conflictPopup');
                if (pop) pop.style.display = 'none';
            };
        })();
