        /* ── Copy Box Text ── */
        function extractBoxText(boxId) {
            const box = document.getElementById(boxId);
            if (!box) return '';
            const clone = box.cloneNode(true);
            const cloneHeader = clone.querySelector('.notes-box-header');
            if (cloneHeader) cloneHeader.remove();
            clone.querySelectorAll('br').forEach(br => br.replaceWith('\\n'));
            clone.querySelectorAll('p, div, li, span.likelihood-line').forEach(el => {
                el.insertAdjacentText('afterend', '\\n');
            });
            return (clone.textContent || clone.innerText || '').replace(/\\n{3,}/g, '\\n\\n').trim();
        }
        window.copyBoxText = function (boxId) {
            const text = extractBoxText(boxId);
            if (!text) { showBoxFeedback(boxId, '⚠️ لا يوجد نص'); return; }
            /* ─ Most reliable copy in Anki: off-screen textarea with real visibility ─ */
            const ta = document.createElement('textarea');
            ta.value = text;
            /* NOT opacity:0 / z-index:-1 — those kill focus in Qt WebEngine */
            ta.style.cssText = [
                'position:fixed',
                'top:-9999px',
                'left:-9999px',
                'width:1px',
                'height:1px',
                'padding:0',
                'border:none',
                'outline:none',
                'resize:none',
                'box-shadow:none',
                'font-size:1px'
            ].join(';');
            document.body.appendChild(ta);
            ta.focus();
            ta.select();
            try { ta.setSelectionRange(0, 99999); } catch (e) { }
            let copied = false;
            try { copied = document.execCommand('copy'); } catch (e) { copied = false; }
            document.body.removeChild(ta);
            if (copied) {
                showBoxFeedback(boxId, '✅ تم النسخ!');
            } else {
                /* Fallback: select the visible rendered text of the box */
                try {
                    const box = document.getElementById(boxId);
                    const hdr = box ? box.querySelector('.notes-box-header') : null;
                    const range = document.createRange();
                    range.selectNodeContents(box);
                    if (hdr) range.setStartAfter(hdr);
                    const sel = window.getSelection();
                    sel.removeAllRanges();
                    sel.addRange(range);
                    copied = document.execCommand('copy');
                    sel.removeAllRanges();
                    showBoxFeedback(boxId, copied ? '✅ تم النسخ!' : '❌ تعذّر النسخ');
                } catch (e2) {
                    showBoxFeedback(boxId, '❌ تعذّر النسخ');
                }
            }
        };
        /* ── Send Box to My Notes ── */
        window.sendBoxToMyNotes = function (boxId, label) {
            const box = document.getElementById(boxId);
            if (!box) return;
            
            const clone = box.cloneNode(true);
            // Remove header and button controls in the cloned element
            const header = clone.querySelector('.notes-box-header');
            if (header) header.remove();
            clone.querySelectorAll('button, .notes-box-actions').forEach(el => el.remove());
            
            const htmlContent = clone.innerHTML.trim();
            if (!htmlContent) return;
            
            // Build prefix
            const entry = '<b>[' + label + ']:</b><br>' + htmlContent;
            
            // Merge with existing notes
            const pText = document.getElementById('qmetaInner') ? document.getElementById('qmetaInner').textContent : '';
            let pfx = pText.replace(/[^a-zA-Z0-9]/g, '');
            if (!pfx || pfx === 'Q') {
                const rawQ = document.getElementById('questionBox') ? document.getElementById('questionBox').textContent : '';
                let hash = 0;
                for (let i = 0; i < rawQ.length; i++) { hash = ((hash << 5) - hash) + rawQ.charCodeAt(i); hash |= 0; }
                pfx = 'H' + Math.abs(hash).toString(36);
            }
            const key = 'anki_notes_' + pfx;
            let existing = '';
            try { existing = localStorage.getItem(key) || ''; } catch (e) { }
            
            const separator = existing ? '<br><hr><br>' : '';
            const newNote = existing + separator + entry;
            
            try { localStorage.setItem(key, newNote); } catch (e) { }
            try { pycmd('setfield:My Notes:' + newNote); } catch (e) { }
            
            // Update display
            const displayBox = document.getElementById('personalNotesDisplayBox');
            const displayText = document.getElementById('personalNotesDisplayText');
            const notesBtn = document.getElementById('personalNotesBtn');
            if (displayText) displayText.innerHTML = newNote;
            if (displayBox) displayBox.style.display = 'block';
            if (notesBtn) notesBtn.classList.add('has-notes');
            showBoxFeedback(boxId, '✅ أُضيف لملاحظاتي!');
        };
        function showBoxFeedback(boxId, msg) {
            const box = document.getElementById(boxId);
            if (!box) return;
            let fb = box.querySelector('.nb-feedback');
            if (!fb) {
                fb = document.createElement('span');
                fb.className = 'nb-feedback';
                fb.style.cssText = 'font-size:0.78em;color:#34d399;margin-right:8px;font-weight:700;transition:opacity 0.5s;';
                const header = box.querySelector('.notes-box-header');
                if (header) header.appendChild(fb);
            }
            fb.textContent = msg;
            fb.style.opacity = '1';
            setTimeout(() => { fb.style.opacity = '0'; setTimeout(() => { fb.textContent = ''; }, 500); }, 1800);
        }
